class Solution {
public:
    vector<int> maximumCount(vector<int>& nums, vector<vector<int>>& queries) {
        vector<int> result;
        for (auto& query : queries) {
            nums[query[0]] = query[1];
            int maxCount = 0;
            for (int k = 1; k < nums.size(); k++) {
                unordered_set<int> prefix, suffix;
                for (int i = 0; i < k; i++) {
                    if (isPrime(nums[i])) prefix.insert(nums[i]);
                }
                for (int i = k; i < nums.size(); i++) {
                    if (isPrime(nums[i])) suffix.insert(nums[i]);
                }
                maxCount = max(maxCount, (int)prefix.size() + (int)suffix.size());
            }
            result.push_back(maxCount);
        }
        return result;
    }

    bool isPrime(int num) {
        if (num <= 1) return false;
        if (num == 2) return true;
        if (num % 2 == 0) return false;
        for (int i = 3; i * i <= num; i += 2) {
            if (num % i == 0) return false;
        }
        return true;
    }
};

